<?php namespace App\Repositories\Attendance;use App\Repositories\BaseRepository;use App\Models\Attendance\Holiday;use Illuminate\Database\Eloquent\Collection;class HolidayRepository extends BaseRepository{    public function __construct(Holiday $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByYear(int $year): Collection    {        return $this->query()->whereYear('date', $year)->orderBy('date', 'asc')->get();    }    public function getUpcomingHolidays(int $limit = 10): Collection    {        return $this->query()->where('date', '>=', now())->orderBy('date', 'asc')->limit($limit)->get();    }    public function getPastHolidays(): Collection    {        return $this->query()->where('date', '<', now())->orderBy('date', 'desc')->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('date', [$startDate, $endDate])->orderBy('date', 'asc')->get();    }    public function checkIsHoliday(string $date): bool    {        return $this->query()->whereDate('date', $date)->exists();    }    public function findByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function searchHolidays(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }}